#nullable enable // autogenerated

using MVZ2.GameContent.Bosses;
using MVZ2.GameContent.Fragments;
using MVZ2.GameContent.Talk;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Bosses;
using MVZ2.Vanilla.Effects;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Pickups;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Pickups
{
    [AutoEntityBehaviourDefinition(VanillaPickupNames.lockedChestPickup)]
    public class LockedChestPickup : EntityBehaviourDefinition
    {
        public LockedChestPickup(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.Timeout = entity.GetMaxTimeout();
        }
        public override void Update(Entity pickup)
        {
            base.Update(pickup);
            var level = pickup.Level;
            float shadowAlpha = 1;
            float gravity = 1;
            if (pickup.IsCollected())
            {
                UpdateCollected(pickup);

                shadowAlpha = 0;
                gravity = 0;
            }
            else
            {
                var variant = pickup.GetVariant();
                if (variant > VARIANT_FIRST_TIME)
                {
                    pickup.Timeout--;
                    if (pickup.Timeout <= 0)
                    {
                        LockedChest.ReallyDestroy(pickup);
                    }
                }
                else if (pickup.GetEntityTime() > Ticks.FromSeconds(10f))
                {
                    pickup.Collect();
                }
            }
            pickup.SetShadowAlpha(shadowAlpha);
            pickup.SetGravity(gravity);
        }
        private static Vector3 GetMoveTargetPosition(Entity entity)
        {
            var level = entity.Level;
            Vector3 slotPosition = level.GetScreenCenterPosition() + Vector2.down * (entity.GetSize().y * entity.GetFinalDisplayScale().y * 0.5f);
            return new Vector3(slotPosition.x, slotPosition.y - COLLECTED_Z - 15, COLLECTED_Z);
        }
        private void UpdateCollected(Entity pickup)
        {
            switch (GetPickupState(pickup))
            {
                case STATE_JUST_COLLECTED:
                    UpdateJustCollected(pickup);
                    break;
                case STATE_SHAKE:
                    UpdateShake(pickup);
                    break;
                case STATE_LAUNCHED:
                    UpdateLaunched(pickup);
                    break;
            }
        }
        private void MoveToCenter(Entity pickup)
        {
            var level = pickup.Level;
            var collectedTime = pickup.GetCollectedTime();
            var moveTime = level.GetSecondTicks(3);
            float timePercent = collectedTime / (float)moveTime;
            var targetPos = GetMoveTargetPosition(pickup);
            pickup.Velocity = (targetPos - pickup.Position) * 0.05f;
            pickup.SetScale(Vector3.one * Mathf.Lerp(1, 3, timePercent));
            pickup.SetDisplayScale(Vector3.one * Mathf.Lerp(1, 3, timePercent));
            pickup.SetSortingLayer(SortingLayers.collectedPickups);
            pickup.SetSortingOrder(9999);
        }
        private void UpdateJustCollected(Entity pickup)
        {
            MoveToCenter(pickup);

            var timer = GetOrInitStateTimer(pickup);
            if (timer.RunToExpired())
            {
                if (pickup.Level.IsFirstAdventure() && pickup.GetVariant() == VARIANT_FIRST_TIME)
                {
                    SetPickupState(pickup, STATE_TALK_STARTED);
                    pickup.Level.SimpleStartTalk(VanillaTalkID.lockedChestAppear, 0, onSkipped: () =>
                    {
                        StartShake(pickup);
                    },
                    onEnd: () =>
                    {
                        StartShake(pickup);
                    });
                }
                else
                {
                    StartShake(pickup);
                }
            }
        }
        public static void StartShake(Entity pickup)
        {
            SetPickupState(pickup, STATE_SHAKE);

            var level = pickup.Level;
            level.PlayMusic(VanillaMusicID.palaceBoss);
            level.SetMusicVolume(1);
            level.SetSubtrackWeight(0);

            var timer = GetOrInitStateTimer(pickup);
            timer.ResetSeconds(SECONDS_TO_END_SHAKE);
        }
        public static void UpdateShake(Entity pickup)
        {
            var pos = GetMoveTargetPosition(pickup);
            pos.x += pickup.RNG.NextFloat() * 5 - 10;
            pos.y += pickup.RNG.NextFloat() * 5 - 10;
            pos.z += pickup.RNG.NextFloat() * 5 - 10;
            pickup.Position = pos;

            var timer = GetOrInitStateTimer(pickup);
            if (timer.RunToExpired())
            {
                pickup.PlaySound(VanillaSoundID.launch);
                pickup.Position = GetMoveTargetPosition(pickup);
                SetPickupState(pickup, STATE_LAUNCHED);
                timer.ResetSeconds(SECONDS_TO_SPAWN_CHEST);
            }
        }
        public static void UpdateLaunched(Entity pickup)
        {
            pickup.Velocity = Vector3.up * 200;

            var timer = GetOrInitStateTimer(pickup);
            if (timer.RunToExpired())
            {
                var level = pickup.Level;
                var position = level.GetEntityGridPosition(7, 3);
                position.y += 1500;

                var param = new SpawnParams();
                var variant = pickup.GetVariant();
                bool revival = variant > VARIANT_FIRST_TIME;
                if (revival)
                {
                    param.SetProperty(LockedChest.PROP_HAVE_BEEN_PRICKED, true);
                    param.SetProperty(LockedChest.PROP_NEXT_JOKE, LockedChest.JOKE_COUNT);
                    param.SetProperty(LockedChest.PROP_PHASE, LockedChest.PHASE_2);
                    param.SetProperty(LockedChest.PROP_REVIVED_TIMES, variant);
                }

                LockedChest.SmashAppear(level, position, pickup, param)?.Let(e =>
                {
                    e.ApplyBuffForBossRevenge();
                    if (revival)
                    {
                        e.Health = e.GetMaxHealth() * LockedChest.REVIVAL_HEALTH_PERCENTAGE;
                    }
                });
                pickup.Remove();
            }
        }
        public static Entity? Produce(LevelEngine level, Vector3 position, Entity? spawner = null, SpawnParams? param = null)
        {
            return level.Produce(VanillaPickupID.lockedChestPickup, position, spawner, param);
        }
        public static int GetPickupState(Entity entity) => entity.GetProperty<int>(PROP_PICKUP_STATE);
        public static void SetPickupState(Entity entity, int value) => entity.SetProperty(PROP_PICKUP_STATE, value);
        public static FrameTimer? GetStateTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_STATE_TIMER);
        public static void SetStateTimer(Entity entity, FrameTimer? value) => entity.SetProperty(PROP_STATE_TIMER, value);
        public static FrameTimer GetOrInitStateTimer(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer == null)
            {
                timer = new FrameTimer();
                SetStateTimer(entity, timer);
            }
            return timer;
        }
        public const float SECONDS_TO_START_TALK = 5f;
        public const float SECONDS_TO_END_SHAKE = 2f;
        public const float SECONDS_TO_SPAWN_CHEST = 1f;

        public const int VARIANT_FIRST_TIME = 0;

        public const int STATE_JUST_COLLECTED = 0;
        public const int STATE_TALK_STARTED = 1;
        public const int STATE_SHAKE = 2;
        public const int STATE_LAUNCHED = 3;

        private const float COLLECTED_Z = 0;
        public static readonly VanillaEntityPropertyMeta<int> PROP_PICKUP_STATE = new VanillaEntityPropertyMeta<int>("pickup_state");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_STATE_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("state_timer");
    }
}